const stdout = items[0].json.stdout || "";

const expected = {
  "automation-01": [
    "netdata",
    "portainer",
    "uptime-kuma",
    "homepage",
    "watchtower",
    "nginx-proxy-manager",
    "n8n",
    "life-control-center",
    "semaphore",
    "forgejo"
  ],
  "docker-01": [
    "netdata",
    "portainer_agent",
    "dozzle",
    "watchtower",
    "cloudflared",
    "nextcloud-app",
    "nextcloud-redis",
    "nextcloud-db"
  ],
  "colmado-db": [
    "supabase-db",
    "supabase-storage",
    "supabase-meta",
    "supabase-studio",
    "supabase-pooler",
    "realtime-dev.supabase-realtime",
    "supabase-auth",
    "supabase-edge-functions",
    "supabase-kong",
    "supabase-rest",
    "supabase-analytics",
    "supabase-vector",
    "supabase-imgproxy"
  ]
};

const running = {
  "automation-01": {},
  "docker-01": {},
  "colmado-db": {}
};

const offline = {
  "automation-01": false,
  "docker-01": false,
  "colmado-db": false
};

for (const line of stdout.trim().split("\n")) {
  const parts = line.split("|");
  if (parts.length < 2) continue;
  const host = parts[0].trim();
  const nameOrStatus = parts[1].trim();

  if (nameOrStatus === "OFFLINE") {
    offline[host] = true;
    continue;
  }

  if (parts.length >= 3) {
    const status = parts[2].trim();
    if (running[host]) {
      running[host][nameOrStatus] = status;
    }
  }
}

const lines = [];
lines.push("🐳 **Homelab Container Status Report**");
lines.push("");
lines.push(`🕒 Time: ${new Date().toLocaleString("en-US", { timeZone: "America/Santo_Domingo" })}`);
lines.push("");

for (const host of ["automation-01", "docker-01", "colmado-db"]) {
  lines.push(`🖥️ **${host}**`);
  if (offline[host]) {
    lines.push("🚨 Host is offline or SSH connection failed!");
    lines.push("");
    continue;
  }

  const hostExpected = expected[host];
  const hostRunning = running[host];
  let hostOk = true;
  const hostLines = [];

  for (const name of hostExpected) {
    if (hostRunning[name]) {
      hostLines.push(`✅ **${name}**: ${hostRunning[name]}`);
    } else {
      hostLines.push(`🚨 **${name}**: Missing / Not running`);
      hostOk = false;
    }
  }

  if (hostOk) {
    lines.push("✅ All expected containers are running healthy.");
  } else {
    lines.push(...hostLines);
  }
  lines.push("");
}

return [
  {
    json: {
      content: lines.join("\n")
    }
  }
];
